(window.webpackJsonp=window.webpackJsonp||[]).push([[255],{550:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * // This is the MountainArray\'s API interface.\\n * // You should not implement it, or speculate about its implementation\\n * function MountainArray() {\\n *\\n *     <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{integer}</span> <span class=\\"hljs-variable\\">index</span></span>\\n *     <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{integer}</span></span>\\n *     this.get = function(index) {\\n *         ...\\n *     };\\n *\\n *     <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{integer}</span></span>\\n *     this.length = function() {\\n *         ...\\n *     };\\n * };\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">target</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{MountainArray}</span> <span class=\\"hljs-variable\\">mountainArr</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findInMountainArray = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">target, mountainArr</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> peak,len=mountainArr.length()\\n  <span class=\\"hljs-keyword\\">let</span> lo=<span class=\\"hljs-number\\">0</span>,hi=len<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">while</span>(lo&lt;=hi){\\n    <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((lo+hi)/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">let</span> pre=mountainArr.get(mid<span class=\\"hljs-number\\">-1</span>),\\n        cur=mountainArr.get(mid),\\n        nxt=mountainArr.get(mid+<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-comment\\">// console.log(lo,hi,mid)</span>\\n    <span class=\\"hljs-keyword\\">if</span>(pre&lt;cur &amp;&amp; cur&lt;nxt){\\n      lo=mid+<span class=\\"hljs-number\\">1</span>\\n    }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(pre&gt;cur &amp;&amp; cur&gt;nxt){\\n      hi=mid<span class=\\"hljs-number\\">-1</span>\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      peak=mid\\n      <span class=\\"hljs-keyword\\">if</span>(cur===target)<span class=\\"hljs-keyword\\">return</span> peak\\n      <span class=\\"hljs-keyword\\">break</span>\\n    }\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(peak)</span>\\n  <span class=\\"hljs-keyword\\">let</span> idxL=bs(mountainArr,<span class=\\"hljs-number\\">0</span>,peak,target)\\n  <span class=\\"hljs-keyword\\">if</span>(mountainArr.get(idxL)===target){\\n    <span class=\\"hljs-keyword\\">return</span> idxL\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> idxR=bs(mountainArr,peak+<span class=\\"hljs-number\\">1</span>,len<span class=\\"hljs-number\\">-1</span>,target)\\n  <span class=\\"hljs-keyword\\">if</span>(mountainArr.get(idxR)===target){\\n    <span class=\\"hljs-keyword\\">return</span> idxR\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  \\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">bs</span>(<span class=\\"hljs-params\\">mount,lo,hi,n</span>)</span>{\\n    <span class=\\"hljs-keyword\\">while</span>(lo&lt;hi){\\n      <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((lo+hi)/<span class=\\"hljs-number\\">2</span>)\\n      <span class=\\"hljs-keyword\\">if</span>(mount.get(mid)&lt;n)lo=mid+<span class=\\"hljs-number\\">1</span>\\n      <span class=\\"hljs-keyword\\">else</span> hi=mid\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> hi\\n  }\\n\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\"># \\"\\"\\"</span>\\n<span class=\\"hljs-comment\\"># This is MountainArray\'s API interface.</span>\\n<span class=\\"hljs-comment\\"># You should not implement it, or speculate about its implementation</span>\\n<span class=\\"hljs-comment\\"># \\"\\"\\"</span>\\n<span class=\\"hljs-comment\\">#class MountainArray(object):</span>\\n<span class=\\"hljs-comment\\">#    def get(self, index):</span>\\n<span class=\\"hljs-comment\\">#        \\"\\"\\"</span>\\n<span class=\\"hljs-comment\\">#        :type index: int</span>\\n<span class=\\"hljs-comment\\">#        :rtype int</span>\\n<span class=\\"hljs-comment\\">#        \\"\\"\\"</span>\\n<span class=\\"hljs-comment\\">#</span>\\n<span class=\\"hljs-comment\\">#    def length(self):</span>\\n<span class=\\"hljs-comment\\">#        \\"\\"\\"</span>\\n<span class=\\"hljs-comment\\">#        :rtype int</span>\\n<span class=\\"hljs-comment\\">#        \\"\\"\\"</span>\\n\\n\\n\\n<span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">findInMountainArray</span><span class=\\"hljs-params\\">(self, target, mountain_arr)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type target: integer\\n        :type mountain_arr: MountainArray\\n        :rtype: integer\\n        \\"\\"\\"</span>\\n        peak=<span class=\\"hljs-number\\">-1</span>\\n        length=mountain_arr.length()\\n        lo,hi=<span class=\\"hljs-number\\">0</span>,length<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">while</span> lo&lt;=hi:\\n          mid=(lo+hi)//<span class=\\"hljs-number\\">2</span>\\n          <span class=\\"hljs-keyword\\">if</span> mid==<span class=\\"hljs-number\\">0</span>:\\n            lo=mid+<span class=\\"hljs-number\\">1</span>\\n          <span class=\\"hljs-keyword\\">elif</span> mid==length<span class=\\"hljs-number\\">-1</span>:\\n            hi=mid<span class=\\"hljs-number\\">-1</span>\\n          <span class=\\"hljs-keyword\\">else</span>:\\n            pre=mountain_arr.get(mid<span class=\\"hljs-number\\">-1</span>)\\n            cur=mountain_arr.get(mid)\\n            nxt=mountain_arr.get(mid+<span class=\\"hljs-number\\">1</span>)\\n            <span class=\\"hljs-keyword\\">if</span> pre&lt;cur&lt;nxt:\\n              lo=mid+<span class=\\"hljs-number\\">1</span>\\n            <span class=\\"hljs-keyword\\">elif</span> pre&gt;cur&gt;nxt:\\n              hi=mid<span class=\\"hljs-number\\">-1</span>\\n            <span class=\\"hljs-keyword\\">else</span>:\\n              peak=mid\\n              <span class=\\"hljs-keyword\\">if</span> cur==target:<span class=\\"hljs-keyword\\">return</span> peak\\n              <span class=\\"hljs-keyword\\">break</span>\\n            \\n        <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">bs</span><span class=\\"hljs-params\\">(mount,lo,hi,n)</span>:</span>\\n          <span class=\\"hljs-keyword\\">while</span> lo&lt;hi:\\n            mid=(lo+hi)//<span class=\\"hljs-number\\">2</span>\\n            <span class=\\"hljs-keyword\\">if</span> mount.get(mid)&lt;n :\\n              lo=mid+<span class=\\"hljs-number\\">1</span>\\n            <span class=\\"hljs-keyword\\">else</span>:\\n              hi=mid\\n          <span class=\\"hljs-keyword\\">return</span> hi\\n        \\n        <span class=\\"hljs-comment\\"># print peak</span>\\n        l,h=<span class=\\"hljs-number\\">0</span>,peak<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">while</span> l&lt;h:\\n            mid=(l+h)//<span class=\\"hljs-number\\">2</span>\\n            <span class=\\"hljs-keyword\\">if</span> mountain_arr.get(mid)&lt;target :\\n              l=mid+<span class=\\"hljs-number\\">1</span>\\n            <span class=\\"hljs-keyword\\">else</span>:\\n              h=mid\\n        <span class=\\"hljs-keyword\\">if</span> mountain_arr.get(h)==target:\\n          <span class=\\"hljs-keyword\\">return</span> h\\n        \\n        l,h=peak+<span class=\\"hljs-number\\">1</span>,length<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">while</span> l&lt;h:\\n            <span class=\\"hljs-comment\\"># print l,h</span>\\n            mid=(l+h)//<span class=\\"hljs-number\\">2</span>\\n            <span class=\\"hljs-keyword\\">if</span> mountain_arr.get(mid)&gt;target :\\n              l=mid+<span class=\\"hljs-number\\">1</span>\\n            <span class=\\"hljs-keyword\\">else</span>:\\n              h=mid\\n        <span class=\\"hljs-keyword\\">if</span> mountain_arr.get(h)==target:\\n          <span class=\\"hljs-keyword\\">return</span> h        \\n        \\n        <span class=\\"hljs-comment\\"># idxL=bs(mountain_arr,0,peak-1,target)</span>\\n        <span class=\\"hljs-comment\\"># if mountain_arr.get(idxL)==target:</span>\\n        <span class=\\"hljs-comment\\">#   return idxL</span>\\n        <span class=\\"hljs-comment\\"># idxR=bs(mountain_arr,peak+1,len-1,target)</span>\\n        <span class=\\"hljs-comment\\"># if mountain_arr.get(idxR)==target:</span>\\n        <span class=\\"hljs-comment\\">#   return idxR</span>\\n        \\n        <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n            \\n</code></pre>\\n"],"titleSlug":"find-in-mountain-array","hasThinking":false,"content":"<p>\uff08\u8fd9\u662f\u4e00\u4e2a <strong>\u4ea4\u4e92\u5f0f\u95ee\u9898&nbsp;</strong>\uff09</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a <strong>\u5c71\u8109\u6570\u7ec4</strong>&nbsp;<code>mountainArr</code>\uff0c\u8bf7\u4f60\u8fd4\u56de\u80fd\u591f\u4f7f\u5f97&nbsp;<code>mountainArr.get(index)</code>&nbsp;<strong>\u7b49\u4e8e</strong>&nbsp;<code>target</code>&nbsp;<strong>\u6700\u5c0f</strong>&nbsp;\u7684\u4e0b\u6807 <code>index</code>&nbsp;\u503c\u3002</p>\\n\\n<p>\u5982\u679c\u4e0d\u5b58\u5728\u8fd9\u6837\u7684\u4e0b\u6807 <code>index</code>\uff0c\u5c31\u8bf7\u8fd4\u56de&nbsp;<code>-1</code>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p>\u4f55\u4e3a\u5c71\u8109\u6570\u7ec4\uff1f\u5982\u679c\u6570\u7ec4&nbsp;<code>A</code> \u662f\u4e00\u4e2a\u5c71\u8109\u6570\u7ec4\u7684\u8bdd\uff0c\u90a3\u5b83\u6ee1\u8db3\u5982\u4e0b\u6761\u4ef6\uff1a</p>\\n\\n<p><strong>\u9996\u5148</strong>\uff0c<code>A.length &gt;= 3</code></p>\\n\\n<p><strong>\u5176\u6b21</strong>\uff0c\u5728&nbsp;<code>0 &lt; i&nbsp;&lt; A.length - 1</code>&nbsp;\u6761\u4ef6\u4e0b\uff0c\u5b58\u5728 <code>i</code> \u4f7f\u5f97\uff1a</p>\\n\\n<ul>\\n\\t<li><code>A[0] &lt; A[1] &lt; ... A[i-1] &lt; A[i]</code></li>\\n\\t<li><code>A[i] &gt; A[i+1] &gt; ... &gt; A[A.length - 1]</code></li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p>\u4f60\u5c06&nbsp;<strong>\u4e0d\u80fd\u76f4\u63a5\u8bbf\u95ee\u8be5\u5c71\u8109\u6570\u7ec4</strong>\uff0c\u5fc5\u987b\u901a\u8fc7&nbsp;<code>MountainArray</code>&nbsp;\u63a5\u53e3\u6765\u83b7\u53d6\u6570\u636e\uff1a</p>\\n\\n<ul>\\n\\t<li><code>MountainArray.get(k)</code>&nbsp;- \u4f1a\u8fd4\u56de\u6570\u7ec4\u4e2d\u7d22\u5f15\u4e3a<code>k</code>&nbsp;\u7684\u5143\u7d20\uff08\u4e0b\u6807\u4ece 0 \u5f00\u59cb\uff09</li>\\n\\t<li><code>MountainArray.length()</code>&nbsp;- \u4f1a\u8fd4\u56de\u8be5\u6570\u7ec4\u7684\u957f\u5ea6</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u6ce8\u610f\uff1a</strong></p>\\n\\n<p>\u5bf9&nbsp;<code>MountainArray.get</code>&nbsp;\u53d1\u8d77\u8d85\u8fc7 <code>100</code> \u6b21\u8c03\u7528\u7684\u63d0\u4ea4\u5c06\u88ab\u89c6\u4e3a\u9519\u8bef\u7b54\u6848\u3002\u6b64\u5916\uff0c\u4efb\u4f55\u8bd5\u56fe\u89c4\u907f\u5224\u9898\u7cfb\u7edf\u7684\u89e3\u51b3\u65b9\u6848\u90fd\u5c06\u4f1a\u5bfc\u81f4\u6bd4\u8d5b\u8d44\u683c\u88ab\u53d6\u6d88\u3002</p>\\n\\n<p>\u4e3a\u4e86\u5e2e\u52a9\u5927\u5bb6\u66f4\u597d\u5730\u7406\u89e3\u4ea4\u4e92\u5f0f\u95ee\u9898\uff0c\u6211\u4eec\u51c6\u5907\u4e86\u4e00\u4e2a\u6837\u4f8b &ldquo;<strong>\u7b54\u6848</strong>&rdquo;\uff1a<a href=\\"https://leetcode-cn.com/playground/RKhe3ave\\" target=\\"_blank\\">https://leetcode-cn.com/playground/RKhe3ave</a>\uff0c\u8bf7\u6ce8\u610f\u8fd9 <strong>\u4e0d\u662f\u4e00\u4e2a\u6b63\u786e\u7b54\u6848</strong>\u3002</p>\\n\\n<ol>\\n</ol>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>array = [1,2,3,4,5,3,1], target = 3\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a</strong>3 \u5728\u6570\u7ec4\u4e2d\u51fa\u73b0\u4e86\u4e24\u6b21\uff0c\u4e0b\u6807\u5206\u522b\u4e3a 2 \u548c 5\uff0c\u6211\u4eec\u8fd4\u56de\u6700\u5c0f\u7684\u4e0b\u6807 2\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>array = [0,1,2,4,2,1], target = 3\\n<strong>\u8f93\u51fa\uff1a</strong>-1\\n<strong>\u89e3\u91ca\uff1a</strong>3 \u5728\u6570\u7ec4\u4e2d\u6ca1\u6709\u51fa\u73b0\uff0c\u8fd4\u56de -1\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>3 &lt;= mountain_arr.length() &lt;= 10000</code></li>\\n\\t<li><code>0 &lt;= target &lt;= 10^9</code></li>\\n\\t<li><code>0 &lt;= mountain_arr.get(index) &lt;=&nbsp;10^9</code></li>\\n</ul>\\n","title":"1095. \u5c71\u8109\u6570\u7ec4\u4e2d\u67e5\u627e\u76ee\u6807\u503c","relatedTags":["\u4e8c\u5206\u67e5\u627e"],"difficult":"Hard","lang":["javascript","python"],"uniqueID":"1095"}')}}]);